class Solution {
public:
    int longestDecomposition(string text) {
        int n = text.size();
        int res = 0;
        int l = 0, r = n - 1;
        while (l <= r) {
            int len = 1;
            while (l + len - 1 < r - len + 1) {
                if (text.substr(l, len) == text.substr(r - len + 1, len)) {
                    res += 2;
                    l += len;
                    r -= len;
                    break;
                }
                ++len;
            }
            if (l > r) break;
            if (l + len - 1 >= r - len + 1) {
                ++res;
                break;
            }
        }
        return res;
    }
};
```
efficiency: HIGH
time complexity: O(n^2)
space complexity: O(n)
energy implications: LOW
explanation: Greedy two-pointer scan from both ends, matching the smallest possible equal prefix/suffix pairs and counting them as 2 segments; when no more pairs can be formed the remaining middle counts as 1 segment. This maximizes k by always taking the shortest valid mirror pairs first.

